const initCopyCode=()=>{HTMLElement.prototype.wrap=function(e){this.parentNode.insertBefore(e,this),this.parentNode.removeChild(this),e.appendChild(this)},document.querySelectorAll("figure.highlight").forEach(e=>{const o=document.createElement("div"),i=(e.wrap(o),o.classList.add("highlight-container"),o.insertAdjacentHTML("beforeend",'<div class="copy-button"><i class="fa-regular fa-copy"></i></div>'),o.insertAdjacentHTML("beforeend",'<div class="fold-button"><i class="fa-solid fa-chevron-down"></i></div>'),o.querySelector(".copy-button")),t=o.querySelector(".fold-button");i.addEventListener("click",()=>{const e=[...o.querySelectorAll(".code .line")];var t=e.map(e=>e.innerText).join("\n");navigator.clipboard.writeText(t),i.querySelector("i").className="fa-regular fa-check",setTimeout(()=>{i.querySelector("i").className="fa-regular fa-copy"},1e3)}),t.addEventListener("click",()=>{o.classList.toggle("folded"),t.querySelector("i").className=o.classList.contains("folded")?"fa-solid fa-chevron-up":"fa-solid fa-chevron-down"})})};export default initCopyCode;